    }

    val visited = LongArray(n.toInt()) { Long.MAX_VALUE }
    visited[0] = 0

    val heap = PriorityQueue<Pair<Int, Long>>(compareBy { it.second })
    heap.add(Pair(0, 0))

    while (heap.isNotEmpty()) {
        val (u, currentTime) = heap.poll()

        if (u == n - 1) {
            return currentTime
        }

        if (currentTime > visited[u]) {
            continue
        }

        // Option 1: Stay at current node
        if (currentTime + 1 < visited[u]) {
            visited[u] = currentTime + 1
            heap.add(Pair(u, currentTime + 1))
        }

        // Option 2: Try outgoing edges
        for ((v, start, end) in adj[u]) {
            if (currentTime > end) {
                continue
            }

            val departureTime = maxOf(currentTime, start)
            val arrivalTime = departureTime + 1

            if (arrivalTime < visited[v]) {
                visited[v] = arrivalTime
                heap.add(Pair(v, arrivalTime))
            }
        }
    }

    return if (visited[n.toInt() - 1] != Long.MAX_VALUE) visited[n.toInt() - 1] else -1
}
